const today = new Date();
today.setHours(0, 0, 0, 0);

const tomorrow = new Date(today);
tomorrow.setDate(tomorrow.getDate() + 1);

const dayAfter = new Date(today);
dayAfter.setDate(dayAfter.getDate() + 2);

const results = [];

for (const item of $input.all()) {
  const appt = item.json;
  const starts = new Date(appt.starts_at);
  const startsDay = new Date(starts);
  startsDay.setHours(0, 0, 0, 0);

  let reminderType = null;
  if (startsDay.getTime() === tomorrow.getTime())      reminderType = 'J-1';
  else if (startsDay.getTime() === dayAfter.getTime()) reminderType = 'J-2';

  if (reminderType) {
    const timeStr = starts.toLocaleTimeString('fr-BE', { hour: '2-digit', minute: '2-digit' });
    const dateStr = starts.toLocaleDateString('fr-BE', { weekday: 'long', day: 'numeric', month: 'long' });
    results.push({
      json: {
        ...appt,
        reminder_type: reminderType,
        starts_formatted: dateStr + ' à ' + timeStr,
        client_name:  appt.profiles?.full_name ?? 'Client',
        client_email: appt.profiles?.email ?? '',
        avocat_name:  appt.avocat?.full_name ?? 'votre avocat',
        avocat_title: appt.avocat?.title ?? '',
      }
    });
  }
}

return results;

